def put(self, request, project_id):
       """
       Update chart configuration for a project.
       Creates a new configuration if it doesn't exist.
       """
       # Get the project and verify ownership
       try:
           project = Project.objects.get(id=project_id, owner=request.user)
       except Project.DoesNotExist:
           return Response(
               {"detail": "Project not found or you don't have permission to access it."},
               status=status.HTTP_404_NOT_FOUND,
           )

       # Get or create chart config
       try:
           chart_config = ChartConfig.objects.get(project=project)
           serializer = ChartConfigSerializer(
               chart_config,
               data=request.data,
               context={"request": request, "project": project},
               partial=False  # PUT requires all fields
           )
       except ChartConfig.DoesNotExist:
           # Create new config
           serializer = ChartConfigSerializer(
               data=request.data,
               context={"request": request, "project": project}
           )

       if serializer.is_valid():
           serializer.save()
           return Response(serializer.data, status=status.HTTP_200_OK)
       else:
           return Response(serializer.errors, status=status.HTTP_400_BAD_REQUEST)

   def patch(self, request, project_id):
       """
       Partially update chart configuration for a project.
       Creates a new configuration if it doesn't exist.
       """
       # Get the project and verify ownership
       try:
           project = Project.objects.get(id=project_id, owner=request.user)
       except Project.DoesNotExist:
           return Response(
               {"detail": "Project not found or you don't have permission to access it."},
               status=status.HTTP_404_NOT_FOUND,
           )

       # Get or create chart config
       try:
           chart_config = ChartConfig.objects.get(project=project)
           serializer = ChartConfigSerializer(
               chart_config,
               data=request.data,
               context={"request": request, "project": project},
               partial=True  # PATCH allows partial updates
           )
       except ChartConfig.DoesNotExist:
           # Create new config with provided data
           serializer = ChartConfigSerializer(
               data=request.data,
               context={"request": request, "project": project}
           )

       if serializer.is_valid():
           serializer.save()
           return Response(serializer.data, status=status.HTTP_200_OK)
       else:
           return Response(serializer.errors, status=status.HTTP_400_BAD_REQUEST)

public function ajax_add_field() {
        // Verify nonce
        if (!wp_verify_nonce($_POST['nonce'], 'form_plugin_nonce')) {
            wp_die('Security check failed');
        }

        // Check user capabilities
        if (!current_user_can('manage_options')) {
            wp_die('Insufficient permissions');
        }

        $form_id = intval($_POST['form_id']);
        $field_type = sanitize_text_field($_POST['field_type']);
        $field_config = $_POST['field_config'];

        // For new forms (form_id = 0), just return success
        if ($form_id === 0) {
            wp_send_json(array(
                'success' => true,
                'message' => 'Field added (will be saved when form is saved)'
            ));
        }

        // Get form builder instance
        $form_builder = new Form_Plugin_Form_Builder();

        // Add field to form
        $result = $form_builder->add_field_to_form($form_id, $field_type, $field_config);

        wp_send_json($result);
    }

