private function array_to_csv_row($array) {
        $csv_row = '';
        $first = true;

        foreach ($array as $value) {
            if (!$first) {
                $csv_row .= ',';
            }

            // Escape value if it contains comma, quote, or newline
            $value = str_replace('"', '""', $value);
            if (strpos($value, ',') !== false || strpos($value, '"') !== false || strpos($value, "\n") !== false) {
                $value = '"' . $value . '"';
            }

            $csv_row .= $value;
            $first = false;
        }

        return $csv_row;
    }

public String exportOrdersToCSV(String status, String paymentStatus, String startDate, String endDate) {
        StringBuilder csv = new StringBuilder();
        csv.append("Order Number,Status,Payment Status,Customer Email,Total Amount,Subtotal,Tax,Shipping,Created At\n");

        // Convert String parameters to appropriate types
        Order.OrderStatus orderStatus = null;
        if (status != null && !status.isEmpty()) {
            try {
                orderStatus = Order.OrderStatus.valueOf(status);
            } catch (IllegalArgumentException e) {
                // Invalid status, will be ignored
            }
        }

        Order.PaymentStatus orderPaymentStatus = null;
        if (paymentStatus != null && !paymentStatus.isEmpty()) {
            try {
                orderPaymentStatus = Order.PaymentStatus.valueOf(paymentStatus);
            } catch (IllegalArgumentException e) {
                // Invalid payment status, will be ignored
            }
        }

        LocalDateTime startDateTime = null;
        if (startDate != null && !startDate.isEmpty()) {
            try {
                startDateTime = LocalDateTime.parse(startDate + "T00:00:00");
            } catch (Exception e) {
                // Invalid date format, will be ignored
            }
        }

        LocalDateTime endDateTime = null;
        if (endDate != null && !endDate.isEmpty()) {
            try {
                endDateTime = LocalDateTime.parse(endDate + "T23:59:59");
            } catch (Exception e) {
                // Invalid date format, will be ignored
            }
        }

        List<Order> orders = orderRepository.findForExport(orderStatus, orderPaymentStatus, startDateTime, endDateTime);

        for (Order order : orders) {
            csv.append(order.getOrderNumber()).append(",");
            csv.append(order.getStatus()).append(",");
            csv.append(order.getPaymentStatus()).append(",");
            csv.append(order.getUser().getEmail()).append(",");
            csv.append(order.getTotalAmount()).append(",");
            csv.append(order.getSubtotal()).append(",");
            csv.append(order.getTaxAmount()).append(",");
            csv.append(order.getShippingAmount()).append(",");
            csv.append(order.getCreatedAt()).append("\n");
        }

        return csv.toString();
    }

def validate_selected_columns(self, value):
        """
        Validate that selected columns exist in the schema and are compatible.
        """
        if not isinstance(value, dict):
            raise serializers.ValidationError("selected_columns must be an object.")

        # Check required fields
        if "x" not in value:
            raise serializers.ValidationError("selected_columns must include 'x' field.")
        if "y" not in value or not isinstance(value["y"], list) or len(value["y"]) == 0:
            raise serializers.ValidationError("selected_columns must include 'y' as a non-empty array.")

        # Validate x column
        x_column = value["x"]
        if not isinstance(x_column, str):
            raise serializers.ValidationError("'x' must be a string (column name).")

        # Validate y columns
        y_columns = value["y"]
        if not isinstance(y_columns, list):
            raise serializers.ValidationError("'y' must be an array of column names.")
        if not all(isinstance(col, str) for col in y_columns):
            raise serializers.ValidationError("All items in 'y' must be strings (column names).")

        # Validate optional fields
        if "groupBy" in value and value["groupBy"] is not None:
            if not isinstance(value["groupBy"], str):
                raise serializers.ValidationError("'groupBy' must be a string (column name) or null.")

        if "label" in value and value["label"] is not None:
            if not isinstance(value["label"], str):
                raise serializers.ValidationError("'label' must be a string (column name) or null.")

        return value

def validate_style(self, value):
        """
        Validate style configuration.
        """
        if value is None:
            return {}

        if not isinstance(value, dict):
            raise serializers.ValidationError("style must be an object.")

        # Validate title
        if "title" in value and value["title"] is not None:
            if not isinstance(value["title"], str):
                raise serializers.ValidationError("'title' must be a string.")
            if len(value["title"]) > 200:
                raise serializers.ValidationError("'title' must be 200 characters or less.")

        # Validate subtitle
        if "subtitle" in value and value["subtitle"] is not None:
            if not isinstance(value["subtitle"], str):
                raise serializers.ValidationError("'subtitle' must be a string.")
            if len(value["subtitle"]) > 200:
                raise serializers.ValidationError("'subtitle' must be 200 characters or less.")

        # Validate axis labels
        if "xAxisLabel" in value and value["xAxisLabel"] is not None:
            if not isinstance(value["xAxisLabel"], str):
                raise serializers.ValidationError("'xAxisLabel' must be a string.")
            if len(value["xAxisLabel"]) > 100:
                raise serializers.ValidationError("'xAxisLabel' must be 100 characters or less.")

        if "yAxisLabel" in value and value["yAxisLabel"] is not None:
            if not isinstance(value["yAxisLabel"], str):
                raise serializers.ValidationError("'yAxisLabel' must be a string.")
            if len(value["yAxisLabel"]) > 100:
                raise serializers.ValidationError("'yAxisLabel' must be 100 characters or less.")

        # Validate colors
        if "colors" in value and value["colors"] is not None:
            if not isinstance(value["colors"], list):
                raise serializers.ValidationError("'colors' must be an array.")
            if len(value["colors"]) > 20:
                raise serializers.ValidationError("'colors' array must have 20 or fewer items.")
            # Validate each color is a valid hex color or named color
            import re
            hex_pattern = re.compile(r'^#([A-Fa-f0-9]{6}|[A-Fa-f0-9]{3})$')
            for color in value["colors"]:
                if not isinstance(color, str):
                    raise serializers.ValidationError("All colors must be strings.")
                if not (hex_pattern.match(color) or color in ['red', 'blue', 'green', 'yellow', 'orange', 'purple', 'pink', 'black', 'white', 'gray', 'grey']):
                    raise serializers.ValidationError(f"Invalid color format: '{color}'. Use hex (#RRGGBB) or named colors.")

        # Validate legend position
        if "legendPosition" in value and value["legendPosition"] is not None:
            valid_positions = ["top", "bottom", "left", "right"]
            if value["legendPosition"] not in valid_positions:
                raise serializers.ValidationError(f"'legendPosition' must be one of: {', '.join(valid_positions)}")

        # Validate boolean fields
        boolean_fields = ["gridlines", "tooltips", "dataLabels"]
        for field in boolean_fields:
            if field in value and value[field] is not None:
                if not isinstance(value[field], bool):
                    raise serializers.ValidationError(f"'{field}' must be a boolean.")

        return value

public function handle_form_submission() {
        // Get form ID
        $form_id = isset($_POST['form_id']) ? intval($_POST['form_id']) : 0;

        if ($form_id === 0) {
            wp_send_json_error(array('message' => __('Invalid form ID.', 'form-plugin')));
        }

        // Verify nonce
        $nonce = isset($_POST['form_plugin_nonce']) ? $_POST['form_plugin_nonce'] : '';
        $nonce_action = 'form_plugin_submit_' . $form_id;

        if (!wp_verify_nonce($nonce, $nonce_action)) {
            wp_send_json_error(array('message' => __('Security check failed.', 'form-plugin')));
        }

        // Get form data
        $form = $this->database->get_form($form_id);

        if (!$form) {
            wp_send_json_error(array('message' => __('Form not found.', 'form-plugin')));
        }

        // Validate captcha
        $captcha_answer = intval($_POST['captcha_answer']);
        $captcha_input = intval($_POST['captcha_input']);

        if ($captcha_input !== $captcha_answer) {
            wp_send_json_error(array('message' => __('Incorrect answer to the math problem.', 'form-plugin')));
        }

        // Get field configuration
        $fields = array();
        if (!empty($form->form_data) && is_array($form->form_data)) {
            if (isset($form->form_data['fields']) && is_array($form->form_data['fields'])) {
                $fields = $form->form_data['fields'];
            }
        }

        // Collect and validate form data
        $submission_data = array();
        $errors = array();

        foreach ($fields as $field) {
            if (!is_array($field)) continue;

            $field_name = $field['id'];
            $field_value = isset($_POST[$field_name]) ? $_POST[$field_name] : '';

            // Validate required fields
            if ($field['required'] && empty($field_value)) {
                $errors[] = sprintf(__('%s is required.', 'form-plugin'), $field['label']);
                continue;
            }

            // Validate email fields
            if ($field['type'] === 'email' && !empty($field_value) && !is_email($field_value)) {
                $errors[] = sprintf(__('%s must be a valid email address.', 'form-plugin'), $field['label']);
                continue;
            }

            $submission_data[$field_name] = array(
                'label' => $field['label'],
                'value' => sanitize_text_field($field_value),
                'type' => $field['type']
            );
        }

        // Return errors if any
        if (!empty($errors)) {
            wp_send_json_error(array('message' => implode('<br>', $errors)));
        }

        // Save submission
        $submission_id = $this->database->save_submission($form_id, $submission_data);

        if ($submission_id) {
            wp_send_json_success(array('message' => __('Form submitted successfully!', 'form-plugin')));
        } else {
            wp_send_json_error(array('message' => __('Failed to save submission.', 'form-plugin')));
        }
    }

const getJobs = async (req, res) => {
    try {
      const {
        search,
        category,
        location,
        employmentType,
        experienceLevel,
        isRemote,
        minSalary,
        maxSalary,
        currency = 'USD',
        sortBy = 'postedAt',
        sortOrder = 'desc',
        page = 1,
        limit = 10
      } = req.query;

      // Build filter object
      const filter = { status: 'active' };

      // Text search
      if (search) {
        filter.$text = { $search: search };
      }

      // Category filter
      if (category) {
        filter.category = category;
      }

      // Location filter
      if (location) {
        filter.location = { $regex: location, $options: 'i' };
      }

      // Employment type filter
      if (employmentType) {
        filter.employmentType = employmentType;
      }

      // Experience level filter
      if (experienceLevel) {
        filter.experienceLevel = experienceLevel;
      }

      // Remote work filter
      if (isRemote !== undefined) {
        filter.isRemote = isRemote === 'true';
      }

      // Salary range filter
      if (minSalary || maxSalary) {
        filter['salaryRange.currency'] = currency;
        if (minSalary && maxSalary) {
          filter.$or = [
            { 'salaryRange.min': { $gte: parseInt(minSalary) } },
            { 'salaryRange.max': { $lte: parseInt(maxSalary) } }
          ];
        } else if (minSalary) {
          filter['salaryRange.min'] = { $gte: parseInt(minSalary) };
        } else if (maxSalary) {
          filter['salaryRange.max'] = { $lte: parseInt(maxSalary) };
        }
      }

      // Build sort object
      const sort = {};
      if (sortBy === 'salary') {
        sort['salaryRange.min'] = sortOrder === 'asc' ? 1 : -1;
      } else {
        sort[sortBy] = sortOrder === 'asc' ? 1 : -1;
      }

      // Calculate pagination
      const skip = (parseInt(page) - 1) * parseInt(limit);

      // Execute query
      const jobs = await JobPosting.find(filter)
        .populate('category', 'name description')
        .populate('employer', 'email profile.firstName profile.lastName profile.organization verificationBadge')
        .sort(sort)
        .skip(skip)
        .limit(parseInt(limit))
        .lean();

      // Get total count for pagination
      const totalJobs = await JobPosting.countDocuments(filter);
      const totalPages = Math.ceil(totalJobs / parseInt(limit));

      res.json({
        success: true,
        data: {
          jobs,
          pagination: {
            currentPage: parseInt(page),
            totalPages,
            totalJobs,
            hasNextPage: parseInt(page) < totalPages,
            hasPrevPage: parseInt(page) > 1
          }
        }
      });
    } catch (error) {
      console.error('Get jobs error:', error);
      res.status(500).json({
        success: false,
        message: 'Failed to fetch jobs',
        error: error.message
      });
    }
  };

const generateSectionHTML = (section, user) => {
    const sectionData = section.data || {};

    console.log(`Processing section: ${section.name}`);
    console.log(`Section data keys:`, Object.keys(sectionData));

    switch (section.name) {
      case 'Profile':
        const summary = sectionData.summary || sectionData.bio || (user && user.bio) || 'Professional summary goes here';
        return `
          <div class="section">
            <h2>Professional Summary</h2>
            <div class="description">${summary}</div>
          </div>
        `;

      case 'Experience':
        const experiences = sectionData.experiences || sectionData.experience || [];
        console.log(`Experience entries: ${experiences.length}`);

        if (!experiences.length) return '';

        const experienceHTML = experiences.map(exp => `
          <div class="item">
            <h3>${exp.position || exp.title || 'Job Title'}</h3>
            <div class="company">${exp.company || 'Company Name'}</div>
            <div class="date">${formatDate(exp.startDate)} - ${exp.isCurrent ? 'Present' : formatDate(exp.endDate)}</div>
            <div class="description">${exp.description || 'Job description'}</div>
          </div>
        `).join('');

        return `
          <div class="section">
            <h2>Experience</h2>
            ${experienceHTML}
          </div>
        `;

      case 'Education':
        const educations = sectionData.educations || sectionData.education || [];
        console.log(`Education entries: ${educations.length}`);

        if (!educations.length) return '';

        const educationHTML = educations.map(edu => `
          <div class="item">
            <h3>${edu.degree || 'Degree'}</h3>
            <div class="company">${edu.institution || 'Institution'}</div>
            <div class="date">${formatDate(edu.startDate)} - ${edu.isCurrent ? 'Present' : formatDate(edu.endDate)}</div>
            ${edu.gpa ? `<div class="description">GPA: ${edu.gpa}</div>` : ''}
          </div>
        `).join('');

        return `
          <div class="section">
            <h2>Education</h2>
            ${educationHTML}
          </div>
        `;

      case 'Skills':
        const technical = sectionData.technical || [];
        const soft = sectionData.soft || [];
        const allSkills = [...technical, ...soft];
        console.log(`Skills: technical=${technical.length}, soft=${soft.length}, total=${allSkills.length}`);

        if (!allSkills.length) return '';

        const skillsHTML = allSkills.map(skill => 
          `<span class="skill">${skill}</span>`
        ).join('');

        return `
          <div class="section">
            <h2>Skills</h2>
            <div class="skills">${skillsHTML}</div>
          </div>
        `;

      case 'Languages':
        const languages = sectionData.languages || [];
        console.log(`Languages: ${languages.length}`);

        if (!languages.length) return '';

        const languagesHTML = languages.map(lang => `
          <div class="item">
            <h3>${lang.name || 'Language'}</h3>
            <div class="description">${lang.level || 'Proficient'}</div>
          </div>
        `).join('');

        return `
          <div class="section">
            <h2>Languages</h2>
            ${languagesHTML}
          </div>
        `;

      case 'Projects':
        const projects = sectionData.projects || [];
        console.log(`Projects: ${projects.length}`);

        if (!projects.length) return '';

        const projectsHTML = projects.map(project => `
          <div class="item">
            <h3>${project.name || 'Project'}</h3>
            <div class="date">${formatDate(project.startDate)} - ${project.endDate ? formatDate(project.endDate) : 'Ongoing'}</div>
            <div class="description">${project.description || 'Project description'}</div>
          </div>
        `).join('');

        return `
          <div class="section">
            <h2>Projects</h2>
            ${projectsHTML}
          </div>
        `;

      case 'Publications':
        const publications = sectionData.publications || [];
        console.log(`Publications: ${publications.length}`);

        if (!publications.length) return '';

        const publicationsHTML = publications.map(pub => {
          const authorsList = pub.authors && Array.isArray(pub.authors) 
            ? pub.authors.map(author => author.name || author).join(', ')
            : 'Authors';
          return `
            <div class="item">
              <h3>${pub.title || 'Publication'}</h3>
              <div class="company">${authorsList}</div>
              <div class="date">${pub.publisher || 'Publisher'} • ${formatDate(pub.publicationDate)}</div>
              ${pub.doi ? `<div class="description">DOI: ${pub.doi}</div>` : ''}
