        return '';
    }
  };

def patch(self, request, project_id):
        """
        Apply edits to the data.
        Body: { "edits": { "row_index": { "column_name": "new_value" } } }
        """
        # Get the project and verify ownership
        try:
            project = Project.objects.get(id=project_id, owner=request.user)
        except Project.DoesNotExist:
            return Response(
                {"detail": "Project not found or you don't have permission to access it."},
                status=status.HTTP_404_NOT_FOUND,
            )

        # Get the data table
        data_table = DataTable.objects.filter(project=project).first()
        if not data_table:
            return Response(
                {"detail": "No data table found for this project. Please upload and parse a file first."},
                status=status.HTTP_404_NOT_FOUND,
            )

        # Validate request data
        edits = request.data.get("edits", {})
        if not isinstance(edits, dict):
            return Response(
                {"detail": "Edits must be an object with row indices as keys."},
                status=status.HTTP_400_BAD_REQUEST,
            )

        # Validate edits against schema and data
        schema = data_table.get_schema()
        data = data_table.get_data_with_edits()
        validation_errors = []

        if data is None:
            return Response(
                {"detail": "Full data not available for editing."},
                status=status.HTTP_400_BAD_REQUEST,
            )

        validated_edits = {}

        for row_index_str, row_edits in edits.items():
            try:
                row_index = int(row_index_str)
            except ValueError:
                validation_errors.append(f"Invalid row index: {row_index_str}")
                continue

            if not (0 <= row_index < len(data)):
                validation_errors.append(f"Row index {row_index} out of range.")
                continue

            if not isinstance(row_edits, dict):
                validation_errors.append(f"Row {row_index}: edits must be an object.")
                continue

            validated_row_edits = {}

            for column_name, new_value in row_edits.items():
                if column_name not in schema:
                    validation_errors.append(f"Row {row_index}: unknown column '{column_name}'.")
                    continue

                expected_type = schema[column_name]

                # Type validation
                if new_value is not None:
                    try:
                        # Convert and validate type
                        if expected_type == "number":
                            if isinstance(new_value, str):
                                new_value = float(new_value)
                            elif not isinstance(new_value, (int, float)):
                                raise ValueError
                        elif expected_type == "boolean":
                            if isinstance(new_value, str):
                                new_value = new_value.lower() in ["true", "1", "yes"]
                            elif not isinstance(new_value, bool):
                                raise ValueError
                        elif expected_type == "string":
                            new_value = str(new_value)
                        # For date, we'll accept string representation for now
                    except (ValueError, TypeError):
                        validation_errors.append(
                            f"Row {row_index}, column '{column_name}': invalid value '{new_value}' for type '{expected_type}'."
                        )
                        continue

                validated_row_edits[column_name] = new_value

            if validated_row_edits:
                validated_edits[str(row_index)] = validated_row_edits

        if validation_errors:
            return Response(
                {
                    "detail": "Validation failed.",
                    "errors": validation_errors
                },
                status=status.HTTP_400_BAD_REQUEST,
            )

        # Apply edits
        try:
            current_edits = data_table.get_edited_data()
            current_edits.update(validated_edits)
            data_table.edited_data_json = current_edits
            data_table.save()

            return Response({
                "detail": f"Successfully applied {len(validated_edits)} row edits.",
                "applied_edits": validated_edits
            })

        except Exception as e:
            return Response(
                {"detail": f"Failed to save edits: {str(e)}"},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR,
            )

private function generate_form_html($form, $atts = array()) {
        $form_id = 'form-plugin-' . $form->id;
        $form_title = !empty($atts['title']) ? $atts['title'] : $form->title;
        $form_description = !empty($atts['description']) ? $atts['description'] : $form->description;

        // Get field configuration
        $fields = array();
        if (!empty($form->form_data) && is_array($form->form_data)) {
            if (isset($form->form_data['fields']) && is_array($form->form_data['fields'])) {
                $fields = $form->form_data['fields'];
            }
        }

        if (empty($fields)) {
            return '<p>' . __('No fields configured for this form.', 'form-plugin') . '</p>';
        }

        // Generate math captcha
        $captcha = $this->generate_math_captcha_data();

        // Get template data
        $template_data = $this->database->get_form_template($form->id);
        $template_id = $template_data['template_id'];
        $customization = $template_data['customization'];

        // Build template classes
        $template_class = 'template-' . $template_id;

        // Build custom styles
        $custom_styles = '';
        if (!empty($customization)) {
            $styles = array();
            if (isset($customization['background_color'])) {
                $styles[] = 'background-color: ' . esc_attr($customization['background_color']);
            }
            if (isset($customization['text_color'])) {
                $styles[] = 'color: ' . esc_attr($customization['text_color']);
            }
            if (isset($customization['border_color'])) {
                $styles[] = 'border-color: ' . esc_attr($customization['border_color']);
            }
            if (!empty($styles)) {
                $custom_styles = ' style="' . implode('; ', $styles) . '"';
            }
        }

        // Start form HTML
        $html = '<div class="form-plugin-container">';

        // Form title
        if ($form_title) {
            $html .= '<h3 class="form-plugin-title">' . esc_html($form_title) . '</h3>';
        }

        // Form description
        if ($form_description) {
            $html .= '<div class="form-plugin-description">' . wp_kses_post($form_description) . '</div>';
        }

        // Form element with template class and custom styles
        $html .= '<form id="' . esc_attr($form_id) . '" class="form-plugin-form ' . esc_attr($template_class) . '" method="post" action=""' . $custom_styles . '>';
        $html .= wp_nonce_field('form_plugin_submit_' . $form->id, 'form_plugin_nonce', true, false);
        $html .= '<input type="hidden" name="form_id" value="' . esc_attr($form->id) . '">';
        $html .= '<input type="hidden" name="captcha_answer" value="' . esc_attr($captcha['answer']) . '">';

        // Render fields
        foreach ($fields as $field) {
            if (is_array($field)) {
                $html .= $this->render_field($field);
            }
        }

        // Math captcha
        $html .= '<div class="form-group form-plugin-captcha">';
        $html .= '<label for="captcha_input" class="form-label">';
        $html .= sprintf(__('What is %d + %d?', 'form-plugin'), $captcha['num1'], $captcha['num2']);
        $html .= ' <span class="required">*</span>';
        $html .= '</label>';
        $html .= '<input type="number" id="captcha_input" name="captcha_input" class="form-control" required>';
        $html .= '<button type="button" class="btn btn-link btn-sm form-plugin-refresh-captcha">';
        $html .= __('Refresh', 'form-plugin');
        $html .= '</button>';
        $html .= '</div>';

        // Submit button with custom color
        $button_style = '';
        if (isset($customization['button_color'])) {
            $button_style = ' style="background-color: ' . esc_attr($customization['button_color']) . '; border-color: ' . esc_attr($customization['button_color']) . ';"';
        }

        $html .= '<div class="form-group form-plugin-submit">';
        $html .= '<button type="submit" class="btn btn-primary form-plugin-submit-btn"' . $button_style . '>';
        $html .= __('Submit Form', 'form-plugin');
        $html .= '</button>';
        $html .= '</div>';

        // Success/Error messages
        $html .= '<div class="form-plugin-messages" style="display: none;"></div>';

        $html .= '</form>';
        $html .= '</div>';

        return $html;
    }

const checkSpamPatterns = (content, authorName, authorEmail) => {
    const spamKeywords = [
      'buy now', 'click here', 'limited time', 'act now',
      'make money', 'get rich', 'free money', 'guaranteed',
      'no credit check', 'risk free', 'winner', 'congratulations'
    ];

    const contentLower = content.toLowerCase();
    const nameLower = authorName.toLowerCase();
    const emailLower = authorEmail.toLowerCase();

    // Check for excessive links
    const linkCount = (content.match(/https?:\/\//g) || []).length;
    if (linkCount > 2) {
      return { isSpam: true, reason: 'Too many links' };
    }

    // Check for spam keywords
    for (const keyword of spamKeywords) {
      if (contentLower.includes(keyword) || nameLower.includes(keyword) || emailLower.includes(keyword)) {
        return { isSpam: true, reason: 'Contains spam keywords' };
      }
    }

    // Check for excessive capitalization
    const upperCaseRatio = (content.match(/[A-Z]/g) || []).length / content.length;
    if (upperCaseRatio > 0.5 && content.length > 20) {
      return { isSpam: true, reason: 'Excessive capitalization' };
    }

    return { isSpam: false };
  };

router.get('/:postId/:blockId/stats', async (req, res) => {
    try {
      const { postId, blockId } = req.params;

      // Validate postId
      if (!postId || !postId.match(/^[0-9a-fA-F]{24}$/)) {
        return sendError(res, 'Invalid post ID', 400);
      }

      // Validate blockId
      if (!blockId || typeof blockId !== 'string' || blockId.trim().length === 0) {
        return sendError(res, 'Invalid block ID', 400);
      }

      // Check if post exists
      const post = await Post.findById(postId);
      if (!post) {
        return sendError(res, 'Post not found', 404);
      }

      // Find the quiz/poll block in the post content
      // Block ID can be the index (as string) or a unique identifier
      let block = null;
      if (/^\d+$/.test(blockId)) {
        // If blockId is a number (as string), use it as array index
        const index = parseInt(blockId);
        if (index >= 0 && index < post.content.length) {
          block = post.content[index];
        }
      } else {
        // Otherwise, search for block by type
        block = post.content.find(b => (b.type === 'quiz' || b.type === 'poll'));
      }

      if (!block || (block.type !== 'quiz' && block.type !== 'poll')) {
        return sendError(res, 'Quiz/Poll block not found in post', 404);
      }

      // Get all responses for this block
      const responses = await QuizResponse.find({ postId, blockId });

      // Calculate statistics
      const totalResponses = responses.length;
      const blockData = block.data;
      const options = blockData.options || [];

      // Initialize option counts
      const optionStats = options.map((opt, index) => ({
        index,
        value: opt.value !== undefined ? opt.value : index,
        text: opt.text,
        count: 0,
        percentage: 0
      }));

      // Count responses
      responses.forEach(response => {
        const answers = Array.isArray(response.answers) ? response.answers : [response.answers];
        answers.forEach(answer => {
          const optionIndex = optionStats.findIndex(stat => 
            stat.value === answer || 
            stat.index === answer || 
            String(stat.value) === String(answer) || 
            String(stat.index) === String(answer)
          );
          if (optionIndex !== -1) {
            optionStats[optionIndex].count++;
          }
        });
      });

      // Calculate percentages
      if (totalResponses > 0) {
        optionStats.forEach(stat => {
          stat.percentage = Math.round((stat.count / totalResponses) * 100 * 10) / 10; // Round to 1 decimal
        });
      }

      sendSuccess(res, {
        totalResponses,
        options: optionStats,
        blockType: block.type,
        question: blockData.question
      }, 'Statistics retrieved successfully');
    } catch (error) {
      console.error('Get quiz statistics error:', error);
      sendError(res, error.message || 'Failed to get statistics', 500);
    }
  });

public function getApplicable()
    {
        try {
            $userId = $this->request->user['user_id'] ?? null;
            $userRole = $this->request->user['role'] ?? null;

            if (!$userId || !$userRole) {
                return $this->unauthorized('Authentication required');
            }

            $storeId = $this->request->getGet('store_id');
            $subtotal = (float) ($this->request->getGet('subtotal') ?? 0);
            $transactionId = $this->request->getGet('transaction_id');

            if (!$storeId) {
                return $this->error('store_id is required', null, 400);
            }

            $now = date('Y-m-d H:i:s');
            $allDiscounts = [];

            // If transaction_id is provided, get product-specific and category discounts
            if ($transactionId) {
                $transactionModel = new \App\Models\TransactionModel();
                $transaction = $transactionModel->getTransactionWithRelations($transactionId);

                if ($transaction && isset($transaction['items'])) {
                    $productIds = [];
                    $categoryIds = [];
                    $productModel = new \App\Models\ProductModel();

                    // Collect product IDs and category IDs from transaction items
                    foreach ($transaction['items'] as $item) {
                        if (isset($item['product_id']) && $item['product_id']) {
                            $productIds[] = (int)$item['product_id'];
                            $product = $productModel->find($item['product_id']);
                            if ($product && isset($product['category_id']) && $product['category_id']) {
                                $categoryIds[] = (int)$product['category_id'];
                            }
                        }
                    }

                    $productIds = array_unique($productIds);
                    $categoryIds = array_unique($categoryIds);

                    // Get product-specific discounts (product_id must NOT be NULL)
                    if (!empty($productIds)) {
                        // Build the query step by step
                        // For product discounts: product_id must be set, category_id must be NULL
                        // Create a completely fresh builder instance
                        $db = \Config\Database::connect();
                        $productDiscountsQuery = $db->table('discounts');

                        $productDiscountsQuery->where('status', 'active')
                            ->where('store_id', $storeId)
                            ->whereIn('product_id', $productIds)
                            ->where('category_id IS NULL', null, false); // Use raw SQL for IS NULL check

                        // Date validation: discount must be currently valid
                        // valid_from must be NULL or <= now (discount has started)
                        // valid_to must be NULL or >= now (discount hasn't expired)
                        $productDiscountsQuery->groupStart()
                            ->where('valid_from IS NULL', null, false)
                            ->orWhere('valid_from <=', $now)
                            ->groupEnd();
                        $productDiscountsQuery->groupStart()
                            ->where('valid_to IS NULL', null, false)
                            ->orWhere('valid_to >=', $now)
                            ->groupEnd();

                        // Min purchase validation
                        if ($subtotal > 0) {
                            $productDiscountsQuery->groupStart()
                                ->where('min_purchase IS NULL', null, false)
                                ->orWhere('min_purchase <=', $subtotal)
                                ->groupEnd();
                        }

                        // Order and execute
                        $productDiscountsQuery->orderBy('value', 'DESC');

                        // Debug: Log the query and parameters
                        log_message('error', '[DiscountController::getApplicable] Product IDs: ' . json_encode($productIds));
                        log_message('error', '[DiscountController::getApplicable] Store ID: ' . $storeId);
                        log_message('error', '[DiscountController::getApplicable] Subtotal: ' . $subtotal);
                        log_message('error', '[DiscountController::getApplicable] Now: ' . $now);
                        log_message('error', '[DiscountController::getApplicable] Category IDs: ' . json_encode($categoryIds));

                        $productDiscounts = $productDiscountsQuery->get()->getResultArray();

                        // Debug logging
                        log_message('error', '[DiscountController::getApplicable] Product discounts found: ' . count($productDiscounts));
                        if (count($productDiscounts) > 0) {
                            log_message('error', '[DiscountController::getApplicable] Product discounts: ' . json_encode($productDiscounts));
                        } else {
                            // Diagnostic queries to find what's filtering out the discounts
                            // Check 1: All product discounts for these products (no filters)
                            $check1Builder = $db->table('discounts');
                            $check1 = $check1Builder
                                ->where('store_id', $storeId)
                                ->whereIn('product_id', $productIds)
                                ->get()->getResultArray();
                            log_message('error', '[DiscountController::getApplicable] Check 1 - All product discounts (no filters): ' . count($check1));
                            if (count($check1) > 0) {
                                log_message('error', '[DiscountController::getApplicable] Check 1 discounts: ' . json_encode($check1));
                            }

                            // Check 2: With status filter
                            $check2Builder = $db->table('discounts');
                            $check2 = $check2Builder
                                ->where('status', 'active')
                                ->where('store_id', $storeId)
                                ->whereIn('product_id', $productIds)
                                ->get()->getResultArray();
                            log_message('error', '[DiscountController::getApplicable] Check 2 - With status=active: ' . count($check2));
                            if (count($check2) > 0) {
                                log_message('error', '[DiscountController::getApplicable] Check 2 discounts: ' . json_encode($check2));
                            }

                            // Check 3: With category_id IS NULL
                            $check3Builder = $db->table('discounts');
                            $check3 = $check3Builder
                                ->where('status', 'active')
                                ->where('store_id', $storeId)
                                ->whereIn('product_id', $productIds)
                                ->where('category_id IS NULL', null, false)
                                ->get()->getResultArray();
                            log_message('error', '[DiscountController::getApplicable] Check 3 - With category_id IS NULL: ' . count($check3));
                            if (count($check3) > 0) {
                                log_message('error', '[DiscountController::getApplicable] Check 3 discounts: ' . json_encode($check3));
                            }

                            // Check 4: With date filters
                            $check4Builder = $db->table('discounts');
                            $check4 = $check4Builder
                                ->where('status', 'active')
                                ->where('store_id', $storeId)
                                ->whereIn('product_id', $productIds)
                                ->where('category_id IS NULL', null, false)
                                ->groupStart()
                                    ->where('valid_from IS NULL', null, false)
                                    ->orWhere('valid_from <=', $now)
                                ->groupEnd()
                                ->groupStart()
                                    ->where('valid_to IS NULL', null, false)
                                    ->orWhere('valid_to >=', $now)
                                ->groupEnd()
                                ->get()->getResultArray();
                            log_message('error', '[DiscountController::getApplicable] Check 4 - With date filters: ' . count($check4));
                            if (count($check4) > 0) {
                                log_message('error', '[DiscountController::getApplicable] Check 4 discounts: ' . json_encode($check4));
                            }
                        }

                        $allDiscounts = array_merge($allDiscounts, $productDiscounts);
                    }

                    // Get category discounts (category_id must NOT be NULL, product_id must be NULL)
                    if (!empty($categoryIds)) {
                        // Create a completely fresh builder instance
                        $db = \Config\Database::connect();
                        $categoryDiscountsBuilder = $db->table('discounts');

                        $categoryDiscountsBuilder->where('status', 'active')
                            ->where('store_id', $storeId)
                            ->where('category_id IS NOT NULL', null, false)
                            ->whereIn('category_id', $categoryIds)
                            ->where('product_id IS NULL', null, false) // Ensure it's category-level, not product-specific
                            ->groupStart()
                                ->where('valid_from IS NULL', null, false)
                                ->orWhere('valid_from <=', $now)
                            ->groupEnd()
                            ->groupStart()
                                ->where('valid_to IS NULL', null, false)
                                ->orWhere('valid_to >=', $now)
                            ->groupEnd();

                        if ($subtotal > 0) {
                            $categoryDiscountsBuilder->groupStart()
                                ->where('min_purchase IS NULL', null, false)
                                ->orWhere('min_purchase <=', $subtotal)
                                ->groupEnd();
                        }

                        $categoryDiscounts = $categoryDiscountsBuilder->orderBy('value', 'DESC')->get()->getResultArray();

                        // Debug logging for category discounts
                        log_message('error', '[DiscountController::getApplicable] Category discounts found: ' . count($categoryDiscounts));
                        if (count($categoryDiscounts) > 0) {
                            log_message('error', '[DiscountController::getApplicable] Category discounts: ' . json_encode($categoryDiscounts));
                        } else {
                            // Diagnostic query for category discounts
                            $catCheckBuilder = $db->table('discounts');
                            $catCheck = $catCheckBuilder
                                ->where('status', 'active')
                                ->where('store_id', $storeId)
                                ->where('category_id IS NOT NULL', null, false)
                                ->whereIn('category_id', $categoryIds)
                                ->where('product_id IS NULL', null, false)
                                ->get()->getResultArray();
                            log_message('error', '[DiscountController::getApplicable] Category check (no date filters): ' . count($catCheck));
                            if (count($catCheck) > 0) {
                                log_message('error', '[DiscountController::getApplicable] Category check discounts: ' . json_encode($catCheck));
                            }
                        }

                        $allDiscounts = array_merge($allDiscounts, $categoryDiscounts);
                    }
                }
            }

            // Get store-wide discounts (always include these)
            $db = \Config\Database::connect();
            $storeDiscountsBuilder = $db->table('discounts');

            $storeDiscountsBuilder->where('status', 'active')
                ->where('store_id', $storeId)
                ->where('product_id IS NULL', null, false)
                ->where('category_id IS NULL', null, false)
                ->groupStart()
                    ->where('valid_from IS NULL', null, false)
                    ->orWhere('valid_from <=', $now)
                ->groupEnd()
                ->groupStart()
                    ->where('valid_to IS NULL', null, false)
                    ->orWhere('valid_to >=', $now)
                ->groupEnd();

            if ($subtotal > 0) {
                $storeDiscountsBuilder->groupStart()
                    ->where('min_purchase IS NULL', null, false)
                    ->orWhere('min_purchase <=', $subtotal)
                    ->groupEnd();
            }

            $storeDiscounts = $storeDiscountsBuilder->orderBy('value', 'DESC')->get()->getResultArray();
            $allDiscounts = array_merge($allDiscounts, $storeDiscounts);

            // Remove duplicates and sort by priority: product > category > store-wide
            $uniqueDiscounts = [];
            $seenIds = [];
            foreach ($allDiscounts as $discount) {
                if (!in_array($discount['id'], $seenIds)) {
                    $uniqueDiscounts[] = $discount;
                    $seenIds[] = $discount['id'];
                }
            }

            // Sort by priority: product discounts first, then category, then store-wide
            usort($uniqueDiscounts, function($a, $b) {
                $priorityA = !empty($a['product_id']) ? 1 : (!empty($a['category_id']) ? 2 : 3);
                $priorityB = !empty($b['product_id']) ? 1 : (!empty($b['category_id']) ? 2 : 3);

                if ($priorityA !== $priorityB) {
                    return $priorityA - $priorityB;
                }

                // If same priority, sort by value descending
                return (float)$b['value'] <=> (float)$a['value'];
            });

            return $this->success($uniqueDiscounts, 'Applicable discounts retrieved successfully');

        } catch (\Exception $e) {
            log_message('error', '[DiscountController::getApplicable] Error: ' . $e->getMessage());
            return $this->error('An error occurred while retrieving applicable discounts: ' . $e->getMessage(), null, 500);
        }
    }

public function show($id = null)
    {
        try {
            $userId = $this->request->user['user_id'] ?? null;
            $userRole = $this->request->user['role'] ?? null;

            if (!$userId || !$userRole) {
                return $this->unauthorized('Authentication required');
            }

            if (!in_array($userRole, ['admin', 'manager'])) {
                return $this->forbidden('Only managers and admins can view discounts');
            }

            $discount = $this->discountModel->find($id);
            if (!$discount) {
                return $this->notFound('Discount not found');
            }

            return $this->success($discount, 'Discount retrieved successfully');

        } catch (\Exception $e) {
